def _snowflake_ai_model_context_to_nested(
    snowflake_ai_model_context: SnowflakeAIModelContext,
) -> SnowflakeAIModelContextNested:
    """Convert flat SnowflakeAIModelContext to nested format."""
    attrs = SnowflakeAIModelContextAttributes()
    _populate_snowflake_ai_model_context_attrs(attrs, snowflake_ai_model_context)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        snowflake_ai_model_context,
        _SNOWFLAKE_AI_MODEL_CONTEXT_REL_FIELDS,
        SnowflakeAIModelContextRelationshipAttributes,
    )
    return SnowflakeAIModelContextNested(
        guid=snowflake_ai_model_context.guid,
        type_name=snowflake_ai_model_context.type_name,
        status=snowflake_ai_model_context.status,
        version=snowflake_ai_model_context.version,
        create_time=snowflake_ai_model_context.create_time,
        update_time=snowflake_ai_model_context.update_time,
        created_by=snowflake_ai_model_context.created_by,
        updated_by=snowflake_ai_model_context.updated_by,
        classifications=snowflake_ai_model_context.classifications,
        classification_names=snowflake_ai_model_context.classification_names,
        meanings=snowflake_ai_model_context.meanings,
        labels=snowflake_ai_model_context.labels,
        business_attributes=snowflake_ai_model_context.business_attributes,
        custom_attributes=snowflake_ai_model_context.custom_attributes,
        pending_tasks=snowflake_ai_model_context.pending_tasks,
        proxy=snowflake_ai_model_context.proxy,
        is_incomplete=snowflake_ai_model_context.is_incomplete,
        provenance_type=snowflake_ai_model_context.provenance_type,
        home_id=snowflake_ai_model_context.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _snowflake_ai_model_context_from_nested(
    nested: SnowflakeAIModelContextNested,
) -> SnowflakeAIModelContext:
    """Convert nested format to flat SnowflakeAIModelContext."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SnowflakeAIModelContextAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SNOWFLAKE_AI_MODEL_CONTEXT_REL_FIELDS,
        SnowflakeAIModelContextRelationshipAttributes,
    )
    return SnowflakeAIModelContext(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_snowflake_ai_model_context_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _snowflake_ai_model_context_to_nested_bytes(
    snowflake_ai_model_context: SnowflakeAIModelContext, serde: Serde
) -> bytes:
    """Convert flat SnowflakeAIModelContext to nested JSON bytes."""
    return serde.encode(
        _snowflake_ai_model_context_to_nested(snowflake_ai_model_context)
    )


def _snowflake_ai_model_context_from_nested_bytes(
    data: bytes, serde: Serde
) -> SnowflakeAIModelContext:
    """Convert nested JSON bytes to flat SnowflakeAIModelContext."""
    nested = serde.decode(data, SnowflakeAIModelContextNested)
    return _snowflake_ai_model_context_from_nested(nested)


